import os
import time
import json
import pickle
import requests
from datetime import datetime, timedelta

class Cache:
    def __init__(self, cache_dir='cache'):
        self.cache_dir = cache_dir
        if not os.path.exists(self.cache_dir):
            os.mkdir(self.cache_dir)

    def get_cache_file(self, url):
        return os.path.join(self.cache_dir, url.replace('/', '_') + '.pkl')

    def is_cache_expired(self, url, expiration_time):
        cache_file = self.get_cache_file(url)
        if not os.path.exists(cache_file):
            return True
        if time.time() - os.path.getmtime(cache_file) > expiration_time:
            return True
        return False

    def get(self, url, expiration_time=3600):
        cache_file = self.get_cache_file(url)
        if self.is_cache_expired(url, expiration_time):
            response = requests.get(url)
            data = response.json()
            with open(cache_file, 'wb') as f:
                pickle.dump(data, f)
        else:
            with open(cache_file, 'rb') as f:
                data = pickle.load(f)
        return data

